UPDATE customer c SET follow_time = (SELECT MAX(r.follow_time) FROM follow_up_record r WHERE r.customer_id = c.id) WHERE c.id LIKE 'demo_c_%';
UPDATE opportunity o SET follow_time = (SELECT MAX(r.follow_time) FROM follow_up_record r WHERE r.opportunity_id = o.id) WHERE o.id LIKE 'demo_o_%';

SELECT 'product' AS tbl, COUNT(*) AS cnt FROM product UNION ALL SELECT 'customer', COUNT(*) FROM customer UNION ALL SELECT 'customer_contact', COUNT(*) FROM customer_contact UNION ALL SELECT 'opportunity', COUNT(*) FROM opportunity UNION ALL SELECT 'follow_up_record', COUNT(*) FROM follow_up_record UNION ALL SELECT 'follow_up_plan', COUNT(*) FROM follow_up_plan;
